import React, { useState, useContext, useEffect } from 'react';
import { taxasIRT } from '../data/mockData';
import { AppContext } from '../App';
import { Colaborador } from '../types';

const Processamento: React.FC = () => {
  const { empresa, colaboradores, setMessage } = useContext(AppContext);
  const ativos = colaboradores.filter(c => c.status === 'Ativo');

  const currentYear = new Date().getFullYear();
  const currentDay = new Date().getDate();
  const [selectedMonth, setSelectedMonth] = useState('Janeiro');
  const [selectedYear, setSelectedYear] = useState(currentYear.toString());
  const [selectedDay, setSelectedDay] = useState(currentDay.toString());

  const [showFormModal, setShowFormModal] = useState(false);
  const [showReceiptModal, setShowReceiptModal] = useState(false);
  const [selectedColab, setSelectedColab] = useState<Colaborador | null>(null);

  // New Subsidio Modal state (Replacing prompt)
  const [showNewSubsidioModal, setShowNewSubsidioModal] = useState(false);
  const [tempSubsidioName, setTempSubsidioName] = useState('');

  // Form states
  const [formSalario, setFormSalario] = useState(0);
  const [formFaltas, setFormFaltas] = useState(0);
  const [formAlimentacao, setFormAlimentacao] = useState(0);
  const [formTransporte, setFormTransporte] = useState(0);
  const [formFerias, setFormFerias] = useState(0);
  const [outrosSubsidios, setOutrosSubsidios] = useState<{nome: string, valor: number}[]>([]);
  const [formHorasExtra, setFormHorasExtra] = useState(0);
  const [formBonus, setFormBonus] = useState(0);

  const calcularIRT = (baseSujeitaIRT: number) => {
    const escalao = taxasIRT.find(t => baseSujeitaIRT >= t.minimo && baseSujeitaIRT <= t.maximo);
    if (!escalao) return 0;
    const calc = ((baseSujeitaIRT - escalao.minimo) * (escalao.taxa / 100)) + escalao.parcelaAbt;
    return calc > 0 ? calc : 0;
  };

  const handleStartProcessar = (colab: Colaborador) => {
    setSelectedColab(colab);
    setFormSalario(colab.salarioBase || 0);
    setFormFaltas(0);
    setFormAlimentacao(30000);
    setFormTransporte(20000);
    setFormFerias(0);
    setOutrosSubsidios([]);
    setFormHorasExtra(0);
    setFormBonus(0);
    setShowFormModal(true);
  };

  const handleAddSubsidio = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const value = e.target.value;
    if (value === 'Outro') {
      setShowNewSubsidioModal(true);
    } else if (value !== '') {
      // Check if already exists to avoid duplicates
      if (!outrosSubsidios.find(s => s.nome === value)) {
        setOutrosSubsidios([...outrosSubsidios, { nome: value, valor: 0 }]);
      }
    }
    e.target.value = ''; // Reset select
  };

  const handleCreateCustomSubsidio = () => {
    if (tempSubsidioName.trim()) {
      setOutrosSubsidios([...outrosSubsidios, { nome: tempSubsidioName.trim(), valor: 0 }]);
      setTempSubsidioName('');
      setShowNewSubsidioModal(false);
    }
  };

  const handleUpdateSubsidioValor = (index: number, valor: number) => {
    const newSubsidios = [...outrosSubsidios];
    newSubsidios[index].valor = valor;
    setOutrosSubsidios(newSubsidios);
  };

  const removeOutroSubsidio = (index: number) => {
    setOutrosSubsidios(outrosSubsidios.filter((_, i) => i !== index));
  };

  const handleConfirmForm = (e: React.FormEvent) => {
    e.preventDefault();
    setShowFormModal(false);
    setShowReceiptModal(true);
    // Silent notification or no notification as user is annoyed
  };

  const currentCalc = () => {
    const totalOutros = outrosSubsidios.reduce((acc, curr) => acc + curr.valor, 0);
    const totalBruto = formSalario + formAlimentacao + formTransporte + formFerias + totalOutros + formHorasExtra + formBonus;
    const baseSalarioLiquidoFaltas = formSalario - formFaltas;

    const taxaINSS = empresa?.taxaINSS || 3;
    const valorINSS = baseSalarioLiquidoFaltas * (taxaINSS / 100);
    const baseIRT = baseSalarioLiquidoFaltas - valorINSS + formAlimentacao + formTransporte + formFerias + totalOutros + formHorasExtra + formBonus; 
    const valorIRT = calcularIRT(baseIRT);

    const totalDescontos = valorINSS + valorIRT + formFaltas;
    const salarioLiquido = totalBruto - totalDescontos;

    return { totalBruto, valorINSS, valorIRT, totalDescontos, salarioLiquido };
  };

  const handleImprimir = () => {
    const content = document.getElementById('recibo-para-impressao');
    if (!content) return;

    // Abrir uma nova janela para impressão para garantir que o layout é o correto e visível
    const printWindow = window.open('', '_blank');
    if (!printWindow) return;

    printWindow.document.write(`
      <html>
        <head>
          <title>Recibo de Salário - SALYA</title>
          <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;700;900&display=swap" rel="stylesheet">
          <script src="https://cdn.tailwindcss.com"></script>
          <style>
            body { font-family: 'Inter', sans-serif; padding: 0; margin: 0; }
            @page { size: A4; margin: 0; }
            .receipt-container { width: 210mm; min-height: 297mm; padding: 20mm; box-sizing: border-box; }
          </style>
        </head>
        <body>
          <div class="receipt-container">
            ${content.innerHTML}
          </div>
          <script>
            window.onload = () => {
              window.print();
              window.close();
            }
          </script>
        </body>
      </html>
    `);
    printWindow.document.close();
  };

  const handleGuardar = () => {
    const element = document.getElementById('recibo-para-impressao');
    if (!element) return;

    // @ts-ignore
    const opt = {
      margin: 10,
      filename: `Recibo_${selectedColab?.nome.replace(/ /g, '_')}_${selectedMonth}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 3, useCORS: true },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
    };

    // @ts-ignore
    window.html2pdf().from(element).set(opt).save();
  };

  return (
    <div className="p-8">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h2 className="text-3xl font-black tracking-tight text-slate-800 dark:text-white">Processamento</h2>
          <p className="text-slate-500 text-sm">Controle de pagamentos e emissão de recibos.</p>
        </div>
      </div>

      <div className="flex flex-wrap gap-4 mb-8">
        <div className="bg-white dark:bg-slate-900 px-6 py-3 rounded-2xl border border-slate-200 dark:border-slate-800 flex flex-col min-w-[150px]">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Mês Referência</span>
          <select value={selectedMonth} onChange={e => setSelectedMonth(e.target.value)} className="bg-transparent border-none p-0 focus:ring-0 font-bold text-slate-900 dark:text-white outline-none">
            {['Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho', 'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'].map(m => (
              <option key={m} value={m}>{m}</option>
            ))}
          </select>
        </div>
        <div className="bg-white dark:bg-slate-900 px-6 py-3 rounded-2xl border border-slate-200 dark:border-slate-800 flex flex-col min-w-[120px]">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Ano</span>
          <select value={selectedYear} onChange={e => setSelectedYear(e.target.value)} className="bg-transparent border-none p-0 focus:ring-0 font-bold text-slate-900 dark:text-white outline-none">
            {['2024', '2025', '2026', '2027'].map(y => (
              <option key={y} value={y}>{y}</option>
            ))}
          </select>
        </div>
        <div className="bg-white dark:bg-slate-900 px-6 py-3 rounded-2xl border border-slate-200 dark:border-slate-800 flex flex-col min-w-[100px]">
          <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Dia</span>
          <input type="number" min="1" max="31" value={selectedDay} onChange={e => setSelectedDay(e.target.value)} className="bg-transparent border-none p-0 focus:ring-0 font-bold text-slate-900 dark:text-white outline-none" />
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-100 dark:border-slate-800 overflow-hidden shadow-xl">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 dark:bg-slate-800/50 border-b border-slate-100 dark:border-slate-800">
              <th className="p-6 text-[11px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
              <th className="p-6 text-[11px] font-black text-slate-400 uppercase tracking-widest text-right">Salário Base</th>
              <th className="p-6 text-[11px] font-black text-slate-400 uppercase tracking-widest text-center">Gestão</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
            {ativos.map(c => (
              <tr key={c.id} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/20 transition-all">
                <td className="p-6">
                  <div className="flex items-center gap-4">
                    <div className="size-10 rounded-xl bg-primary/10 flex items-center justify-center text-primary font-black uppercase text-xs">{c.nome.substring(0, 2)}</div>
                    <div>
                      <p className="text-sm font-black text-slate-800 dark:text-white uppercase tracking-tighter">{c.nome}</p>
                      <p className="text-[10px] font-bold text-slate-400 uppercase">{c.cargo}</p>
                    </div>
                  </div>
                </td>
                <td className="p-6 text-right font-black text-slate-700 dark:text-slate-300">{Number(c.salarioBase).toLocaleString()} Kz</td>
                <td className="p-6 text-center">
                  <button onClick={() => handleStartProcessar(c)} className="bg-primary hover:bg-primary/90 text-white px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest shadow-lg shadow-primary/20 transition-all active:scale-95">Processar</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Form Modal */}
      {showFormModal && selectedColab && (
        <div className="fixed inset-0 bg-slate-900/60 flex items-center justify-center z-[90] p-4 backdrop-blur-md">
          <div className="bg-white dark:bg-slate-900 rounded-[32px] max-w-xl w-full max-h-[90vh] overflow-y-auto shadow-2xl">
            <div className="p-10 border-b border-slate-100 dark:border-slate-800 flex items-start justify-between">
              <div>
                <h2 className="font-black text-2xl text-slate-900 dark:text-white uppercase tracking-tighter">Variáveis do Mês</h2>
                <div className="flex items-center gap-2 mt-1">
                  <span className="material-symbols-outlined text-sm text-primary">person</span>
                  <span className="text-primary text-[11px] font-bold uppercase tracking-widest">{selectedColab.nome}</span>
                </div>
              </div>
              <button onClick={() => setShowFormModal(false)} className="size-10 flex items-center justify-center hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors"><span className="material-symbols-outlined text-slate-400">close</span></button>
            </div>

            <form onSubmit={handleConfirmForm} className="p-10 space-y-8">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Salário de Contrato</label>
                <div className="relative">
                  <input required type="text" value={formSalario ? formSalario.toLocaleString('pt-AO') : ''} onChange={e => setFormSalario(Number(e.target.value.replace(/\D/g, '')))} className="w-full px-6 py-4 bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-800 rounded-2xl font-black text-primary text-3xl focus:border-primary outline-none transition-all" />
                  <span className="absolute right-6 top-1/2 -translate-y-1/2 text-slate-300 font-black text-sm uppercase">Kz</span>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Alimentação</label><input type="number" value={formAlimentacao === 0 ? '' : formAlimentacao} onChange={e => setFormAlimentacao(Number(e.target.value))} className="w-full px-5 py-3.5 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-800 rounded-xl font-bold" /></div>
                <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Transporte</label><input type="number" value={formTransporte === 0 ? '' : formTransporte} onChange={e => setFormTransporte(Number(e.target.value))} className="w-full px-5 py-3.5 bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-800 rounded-xl font-bold" /></div>
              </div>

              <div className="space-y-4 pt-4 border-t border-slate-100 dark:border-slate-800">
                <div className="flex items-center justify-between">
                   <h4 className="text-[11px] font-black text-slate-800 dark:text-white uppercase tracking-widest">Subsídios Adicionais</h4>
                   <select 
                     onChange={handleAddSubsidio}
                     className="text-[10px] bg-primary text-white border-none rounded-lg py-1.5 px-3 font-black uppercase tracking-widest cursor-pointer shadow-lg shadow-primary/20 outline-none"
                   >
                     <option value="">+ Seleccionar</option>
                     <option value="Subsídio de Chefia">Chefia</option>
                     <option value="Subsídio de Disponibilidade">Disponibilidade</option>
                     <option value="Gratificação">Gratificação</option>
                     <option value="Outro">Outro personalizado...</option>
                   </select>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  {outrosSubsidios.map((s, idx) => (
                    <div key={idx} className="bg-slate-50 dark:bg-slate-800/50 p-4 rounded-2xl border border-slate-100 dark:border-slate-800 animate-in fade-in slide-in-from-top-2">
                       <div className="flex justify-between items-center mb-2">
                          <label className="text-[10px] font-black text-primary uppercase tracking-widest truncate">{s.nome}</label>
                          <button type="button" onClick={() => removeOutroSubsidio(idx)} className="text-red-400 hover:text-red-600"><span className="material-symbols-outlined text-sm">delete</span></button>
                       </div>
                       <input 
                         type="number" 
                         value={s.valor === 0 ? '' : s.valor} 
                         onChange={e => handleUpdateSubsidioValor(idx, Number(e.target.value))} 
                         className="w-full bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-xl py-2 px-3 font-bold text-sm"
                         placeholder="Valor em Kz"
                       />
                    </div>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-6 pt-6 border-t border-slate-100 dark:border-slate-800">
                <div className="space-y-1.5"><label className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">Horas Extra</label><input type="number" value={formHorasExtra === 0 ? '' : formHorasExtra} onChange={e => setFormHorasExtra(Number(e.target.value))} className="w-full px-5 py-3.5 bg-emerald-50/20 border border-emerald-100 rounded-xl font-bold" /></div>
                <div className="space-y-1.5"><label className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">Bónus</label><input type="number" value={formBonus === 0 ? '' : formBonus} onChange={e => setFormBonus(Number(e.target.value))} className="w-full px-5 py-3.5 bg-emerald-50/20 border border-emerald-100 rounded-xl font-bold" /></div>
              </div>

              <div className="space-y-1.5 pt-4">
                <label className="text-[10px] font-black text-red-500 uppercase tracking-widest">Faltas / Descontos (Total)</label>
                <input type="number" value={formFaltas === 0 ? '' : formFaltas} onChange={e => setFormFaltas(Number(e.target.value))} className="w-full px-6 py-4 bg-red-50/30 border-2 border-red-50 rounded-2xl font-black text-red-600 text-xl" />
              </div>

              <button type="submit" className="w-full py-5 bg-slate-900 hover:bg-black text-white rounded-[20px] font-black flex items-center justify-center gap-3 shadow-2xl transition-all uppercase tracking-[4px] text-xs">
                Processar Salário
              </button>
            </form>
          </div>
        </div>
      )}

      {/* New Subsídio Name Modal - REPLACING PROMPT */}
      {showNewSubsidioModal && (
        <div className="fixed inset-0 bg-slate-900/40 flex items-center justify-center z-[110] p-4 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 rounded-3xl p-8 max-w-sm w-full shadow-2xl border border-slate-100 dark:border-slate-800 scale-100 animate-in zoom-in-95">
            <h3 className="text-lg font-black text-slate-900 dark:text-white uppercase tracking-tighter mb-4">Novo Subsídio</h3>
            <p className="text-xs text-slate-500 mb-6 font-medium">Digite o nome do benefício que deseja adicionar:</p>
            <input 
              autoFocus
              value={tempSubsidioName}
              onChange={e => setTempSubsidioName(e.target.value)}
              className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-700 rounded-xl font-bold mb-6 outline-none focus:border-primary"
              placeholder="Ex: Subsídio de Idiomas"
              onKeyDown={e => e.key === 'Enter' && handleCreateCustomSubsidio()}
            />
            <div className="flex gap-3">
              <button onClick={() => { setShowNewSubsidioModal(false); setTempSubsidioName(''); }} className="flex-1 py-3 font-bold text-slate-400 hover:text-slate-600 uppercase text-[10px] tracking-widest">Cancelar</button>
              <button onClick={handleCreateCustomSubsidio} className="flex-1 py-3 bg-primary text-white rounded-xl font-black uppercase text-[10px] tracking-widest">Adicionar</button>
            </div>
          </div>
        </div>
      )}

      {/* Receipt Modal */}
      {showReceiptModal && selectedColab && (
        <div className="fixed inset-0 bg-slate-900/90 flex items-center justify-center z-[100] p-4 backdrop-blur-xl">
          <div className="bg-white rounded-[40px] max-w-[210mm] w-full max-h-[95vh] overflow-y-auto shadow-2xl relative flex flex-col">
            <div className="p-16 bg-white" id="recibo-para-impressao" style={{ minHeight: '297mm', width: '210mm', boxSizing: 'border-box', margin: '0 auto' }}>

              {/* Receipt Content Re-designed for better print quality and "Patronal" logic */}
              <div className="flex justify-between items-start mb-12">
                <div>
                  <h1 className="text-3xl font-black text-black uppercase tracking-tighter mb-1">{empresa?.nome || 'ENTIDADE'}</h1>
                  <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">NIF: {empresa?.nif || '-'}</p>
                  {empresa?.categoria === 'Particular' && (
                    <span className="bg-indigo-600 text-white text-[9px] font-black uppercase px-3 py-1 rounded-sm tracking-widest">Entidade Patronal</span>
                  )}
                </div>
                <div className="text-right">
                  <div className="bg-black text-white px-8 py-3 rounded-sm inline-block mb-4">
                    <h2 className="text-xl font-black uppercase tracking-[6px]">Recibo</h2>
                  </div>
                  <p className="text-[10px] font-black text-slate-900 uppercase tracking-[2px]">{selectedMonth} / {selectedYear}</p>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-12 mb-16">
                <div>
                  <div className="border-l-2 border-black pl-5">
                    <h3 className="text-[9px] font-black text-slate-300 uppercase tracking-widest mb-1">Beneficiário</h3>
                    <p className="text-lg font-black uppercase text-black">{selectedColab.nome}</p>
                    <p className="text-[10px] font-bold text-slate-500 mt-1 uppercase">{selectedColab.cargo}</p>
                  </div>
                  <div className="mt-8 grid grid-cols-2 gap-4">
                    <div><p className="text-[8px] font-black text-slate-300 uppercase">ID</p><p className="text-[10px] font-bold">{selectedColab.numeroColaborador || '-'}</p></div>
                    <div><p className="text-[8px] font-black text-slate-300 uppercase">INSS</p><p className="text-[10px] font-bold">{selectedColab.inss || '-'}</p></div>
                  </div>
                </div>
                <div className="bg-slate-50 p-8 rounded-2xl">
                  <h3 className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-4">Detalhes de Transferência</h3>
                  <p className="text-[9px] font-bold text-slate-500 uppercase mb-1">IBAN Colaborador</p>
                  <p className="text-sm font-black text-black font-mono tracking-tighter">{selectedColab.iban || '-'}</p>
                  <div className="mt-4 pt-4 border-t border-slate-200">
                    <p className="text-[8px] font-bold text-slate-400 uppercase">Tipo Documento</p>
                    <p className="text-[10px] font-black">Recibo de Vencimento Digital</p>
                  </div>
                </div>
              </div>

              <div className="mb-12">
                <table className="w-full text-[11px] border-collapse">
                  <thead>
                    <tr className="border-b-2 border-black text-black">
                      <th className="py-4 text-left font-black uppercase tracking-widest">Descrição das Remunerações</th>
                      <th className="py-4 text-right font-black uppercase tracking-widest w-32">Iliquido</th>
                      <th className="py-4 text-right font-black uppercase tracking-widest w-32">Deduções</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100">
                    <tr className="font-bold">
                      <td className="py-4">Salário Base (Mensal)</td>
                      <td className="py-4 text-right">{formSalario.toLocaleString('pt-AO')} Kz</td>
                      <td className="py-4 text-right">-</td>
                    </tr>
                    {formAlimentacao > 0 && <tr><td className="py-3">Subsídio de Alimentação</td><td className="py-3 text-right">{formAlimentacao.toLocaleString('pt-AO')} Kz</td><td className="py-3 text-right">-</td></tr>}
                    {formTransporte > 0 && <tr><td className="py-3">Subsídio de Transporte</td><td className="py-3 text-right">{formTransporte.toLocaleString('pt-AO')} Kz</td><td className="py-3 text-right">-</td></tr>}
                    {outrosSubsidios.map((s, i) => (
                      <tr key={i}><td className="py-3">{s.nome}</td><td className="py-3 text-right">{s.valor.toLocaleString('pt-AO')} Kz</td><td className="py-3 text-right">-</td></tr>
                    ))}
                    {formHorasExtra > 0 && <tr><td className="py-3">Trabalho Extraordinário</td><td className="py-3 text-right">{formHorasExtra.toLocaleString('pt-AO')} Kz</td><td className="py-3 text-right">-</td></tr>}
                    {formBonus > 0 && <tr><td className="py-3">Bónus e Gratificações</td><td className="py-3 text-right">{formBonus.toLocaleString('pt-AO')} Kz</td><td className="py-3 text-right">-</td></tr>}

                    <tr className="text-slate-500 italic">
                      <td className="py-3">Segurança Social (Desconto {empresa?.taxaINSS || 3}%)</td>
                      <td className="py-3 text-right">-</td>
                      <td className="py-3 text-right">- {currentCalc().valorINSS.toLocaleString('pt-AO')} Kz</td>
                    </tr>
                    <tr className="text-slate-500 italic">
                      <td className="py-3">Imposto Rendimento Trabalho (IRT)</td>
                      <td className="py-3 text-right">-</td>
                      <td className="py-3 text-right">- {currentCalc().valorIRT.toLocaleString('pt-AO')} Kz</td>
                    </tr>
                    {formFaltas > 0 && <tr className="text-red-500 font-bold"><td className="py-3">Ausências e Faltas Justificadas/Injust.</td><td className="py-3 text-right">-</td><td className="py-3 text-right">- {formFaltas.toLocaleString('pt-AO')} Kz</td></tr>}
                  </tbody>
                  <tfoot>
                    <tr className="border-t-2 border-black font-black text-black uppercase">
                      <td className="py-6">Total Geral</td>
                      <td className="py-6 text-right">{currentCalc().totalBruto.toLocaleString('pt-AO')} Kz</td>
                      <td className="py-6 text-right">{currentCalc().totalDescontos.toLocaleString('pt-AO')} Kz</td>
                    </tr>
                  </tfoot>
                </table>
              </div>

              <div className="flex justify-between items-end mt-4">
                <div className="border-2 border-black p-8 rounded-sm">
                   <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Líquido a Receber</p>
                   <p className="text-4xl font-black text-black tracking-tighter">{currentCalc().salarioLiquido.toLocaleString('pt-AO')} Kz</p>
                </div>
                <div className="text-right text-[8px] font-black text-slate-300 uppercase tracking-[4px]">
                  SALYA HRMS • CLOUD SOLUTIONS
                </div>
              </div>

              <div className="mt-20 pt-8 border-t border-slate-100 flex justify-between items-center opacity-60">
                 <p className="text-[9px] font-bold text-slate-400 italic">Recibo processado pelo software de gestão SALYA</p>
                 <p className="text-[9px] font-bold text-slate-400 uppercase">Processado em: {new Date().toLocaleDateString()}</p>
              </div>
            </div>

            <div className="p-8 bg-slate-900 border-t border-white/10 flex gap-4 sticky bottom-0 z-10 w-full">
              <button onClick={handleGuardar} className="flex-1 py-4 bg-white text-black rounded-2xl font-black flex items-center justify-center gap-3 uppercase tracking-widest text-[10px] active:scale-95 transition-all"><span className="material-symbols-outlined text-base">picture_as_pdf</span> Guardar PDF</button>
              <button onClick={handleImprimir} className="flex-1 py-4 bg-primary text-white rounded-2xl font-black flex items-center justify-center gap-3 uppercase tracking-widest text-[10px] active:scale-95 transition-all"><span className="material-symbols-outlined text-base">print</span> Imprimir Recibo</button>
              <button onClick={() => setShowReceiptModal(false)} className="px-10 py-4 bg-slate-800 text-slate-400 rounded-2xl font-black uppercase tracking-widest text-[10px] hover:text-white transition-colors">Fechar</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Processamento;
